const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const stores = JSON.parse(localStorage.getItem('stores') || '[]');
const currentAccountId = localStorage.getItem('currentAccountId');
const account = accounts.find(a => a.id === currentAccountId) || null;

// CP1: Logged in as the correct user (demo.user1)
const loginCorrect = !!account && account.email === 'demo.user1@example.com';

// Compute nearest store in ZIP 94103 within 5 miles
const zip = '94103';
const maxDistance = 5.0;
const storesInZip = stores.filter(s => String(s.zipCode || '').trim() === zip);
const eligibleStores = storesInZip.filter(s => typeof s.distanceMiles === 'number' && s.distanceMiles <= maxDistance);
eligibleStores.sort((a, b) => a.distanceMiles - b.distanceMiles);
const nearestStore = eligibleStores.length ? eligibleStores[0] : null;

// CP2: Favorite store is set to that nearest eligible store
const favoriteCorrect = loginCorrect && !!nearestStore && account.favoriteStoreId === nearestStore.id;

checkpoints.push({ passed: loginCorrect, weight: 0.4 });
checkpoints.push({ passed: favoriteCorrect, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const currentAccountId = localStorage.getItem('currentAccountId');
const instrumentation = JSON.parse(localStorage.getItem('task2_dashboardAccessed') || 'null');

const newEmail = 'jordan.sample01@example.com';
const newAccount = accounts.find(a => a.email && a.email.toLowerCase() === newEmail) || null;

// CP1: New account was created with correct core fields
const accountCreatedCorrect = !!newAccount &&
  newAccount.fullName === 'Jordan Sample' &&
  newAccount.password === 'StrongCoffee!789' &&
  newAccount.termsAccepted === true;

// CP2: Dashboard access instrumentation matches this new account
const dashboardAccessedCorrect = !!instrumentation && !!newAccount &&
  instrumentation.accountId === newAccount.id &&
  instrumentation.email && instrumentation.email.toLowerCase() === newAccount.email.toLowerCase();

// CP3: Currently logged in as the new account
const loggedInAsNew = !!newAccount && currentAccountId === newAccount.id;

checkpoints.push({ passed: accountCreatedCorrect, weight: 0.4 });
checkpoints.push({ passed: dashboardAccessedCorrect, weight: 0.4 });
checkpoints.push({ passed: loggedInAsNew, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const items = JSON.parse(localStorage.getItem('order_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const currentAccountId = localStorage.getItem('currentAccountId');
const currentOrderId = localStorage.getItem('currentOrderId');
const account = accounts.find(a => a.id === currentAccountId) || null;

// CP1: Logged in as demo.user2
const loginCorrect = !!account && account.email === 'demo.user2@example.com';

// Find current draft order for this account
let currentOrder = null;
if (account && currentOrderId) {
  currentOrder = orders.find(o => o.id === currentOrderId && o.status === 'draft' && o.accountId === account.id) || null;
}
if (account && !currentOrder) {
  currentOrder = orders.find(o => o.status === 'draft' && o.accountId === account.id) || null;
}

let orderItems = [];
if (currentOrder) {
  orderItems = items.filter(i => i.orderId === currentOrder.id);
}

// CP2: Order contains at least one medium latte (any latte product, size medium)
const latteItems = orderItems.filter(i => {
  const prod = products.find(p => p.id === i.productId) || null;
  return prod && prod.menuCategoryId === 'lattes' && i.size === 'medium' && i.quantity >= 1;
});
const hasMediumLatte = loginCorrect && !!currentOrder && latteItems.length > 0;

// CP3: Pickup time is set to tomorrow between 8:00–9:00 and exactly 08:30
let pickupCorrect = false;
if (loginCorrect && currentOrder && currentOrder.pickupDateTime) {
  const dt = new Date(currentOrder.pickupDateTime);
  if (!isNaN(dt.getTime())) {
    let isTomorrow = true;
    if (metadata && metadata.baselineDate) {
      const baseline = new Date(metadata.baselineDate + 'T00:00:00Z');
      const tomorrow = new Date(baseline.getTime() + 24 * 60 * 60 * 1000);
      isTomorrow = dt.getUTCFullYear() === tomorrow.getUTCFullYear() &&
                   dt.getUTCMonth() === tomorrow.getUTCMonth() &&
                   dt.getUTCDate() === tomorrow.getUTCDate();
    }
    const hours = dt.getUTCHours();
    const minutes = dt.getUTCMinutes();
    const withinWindow = hours === 8; // 08:00–08:59 UTC
    const isTargetTime = hours === 8 && minutes === 30;
    pickupCorrect = isTomorrow && withinWindow && isTargetTime;
  }
}

checkpoints.push({ passed: loginCorrect, weight: 0.3 });
checkpoints.push({ passed: hasMediumLatte, weight: 0.4 });
checkpoints.push({ passed: pickupCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checklists = [];
const checkpoints = checklists; // alias to match pattern

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const items = JSON.parse(localStorage.getItem('order_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

const currentAccountId = localStorage.getItem('currentAccountId');
const account = accounts.find(a => a.id === currentAccountId) || null;

// CP1: Logged in as demo.user3
const loginCorrect = !!account && account.email === 'demo.user3@example.com';

// Determine the cheapest large drink item from non-draft orders
const pastOrderIds = orders.filter(o => o.status && o.status !== 'draft').map(o => o.id);

const largeDrinkItems = items.filter(i => {
  if (pastOrderIds.indexOf(i.orderId) === -1) return false;
  if (i.size !== 'large') return false;
  const prod = products.find(p => p.id === i.productId) || null;
  return prod && prod.baseType === 'drink';
});

largeDrinkItems.sort((a, b) => a.unitPrice - b.unitPrice);
const cheapest = largeDrinkItems.length ? largeDrinkItems[0] : null;

// Check for a draft order for this account containing that cheapest large drink
let reorderedCorrect = false;
if (loginCorrect && cheapest) {
  const draftOrders = orders.filter(o => o.status === 'draft' && o.accountId === account.id);
  for (let d = 0; d < draftOrders.length && !reorderedCorrect; d++) {
    const oId = draftOrders[d].id;
    const draftItems = items.filter(i => i.orderId === oId);
    reorderedCorrect = draftItems.some(i =>
      i.productId === cheapest.productId &&
      i.size === cheapest.size &&
      i.unitPrice === cheapest.unitPrice &&
      i.quantity >= 1 &&
      i.isRewardRedemption === false
    );
  }
}

checkpoints.push({ passed: loginCorrect, weight: 0.3 });
checkpoints.push({ passed: reorderedCorrect, weight: 0.7 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const cards = JSON.parse(localStorage.getItem('payment_cards') || '[]');

const currentAccountId = localStorage.getItem('currentAccountId');
const account = accounts.find(a => a.id === currentAccountId) || null;

// CP1: Logged in as demo.user4
const loginCorrect = !!account && account.email === 'demo.user4@example.com';

// Cards belonging to this account (runtime cards have accountId)
const accountCards = cards.filter(c => c.accountId === (account && account.id) && c.isActive);

// Find newly added Visa 4242 card with specified expiry and billing ZIP
const newCard = accountCards.find(c =>
  c.cardBrand === 'visa' &&
  c.last4 === '4242' &&
  c.expMonth === 12 &&
  c.expYear === 2030 &&
  c.billingZip === '94103'
) || null;

const cardAddedCorrect = loginCorrect && !!newCard;

// CP3: That new card is set as the default for the account
const defaultSetCorrect = cardAddedCorrect &&
  newCard.isDefault === true &&
  account.defaultPaymentCardId === newCard.id;

checkpoints.push({ passed: loginCorrect, weight: 0.3 });
checkpoints.push({ passed: cardAddedCorrect, weight: 0.4 });
checkpoints.push({ passed: defaultSetCorrect, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const rewards = JSON.parse(localStorage.getItem('rewards') || '[]');
const redemptions = JSON.parse(localStorage.getItem('reward_redemptions') || '[]');

const currentAccountId = localStorage.getItem('currentAccountId');
const account = accounts.find(a => a.id === currentAccountId) || null;

// CP1: Logged in as demo.user5
const loginCorrect = !!account && account.email === 'demo.user5@example.com';

// Redemptions for this account (runtime redemptions have accountId)
const accountRedemptions = redemptions.filter(r => r.accountId === (account && account.id));

// Qualifying redemptions: bakery, available, price < 5, rating >= 4, not cancelled
const qualifyingRedemptions = accountRedemptions.filter(r => {
  const reward = rewards.find(w => w.id === r.rewardId) || null;
  if (!reward) return false;
  if (reward.category !== 'bakery') return false;
  if (!reward.isAvailable) return false;
  if (typeof reward.price !== 'number' || reward.price >= 5) return false;
  if (typeof reward.rating === 'number' && reward.rating < 4) return false;
  if (r.status === 'cancelled') return false;
  return true;
});

const redeemedQualifyingReward = loginCorrect && qualifyingRedemptions.length >= 1;

checkpoints.push({ passed: loginCorrect, weight: 0.3 });
checkpoints.push({ passed: redeemedQualifyingReward, weight: 0.7 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const prefs = JSON.parse(localStorage.getItem('notification_preferences') || '[]');

const currentAccountId = localStorage.getItem('currentAccountId');
