const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const currentAccountId = localStorage.getItem('currentAccountId');

// Target account by email
const targetAccount = accounts.find(a => a.email === 'demo.user7@example.com') || null;

// CP1: Password changed to the new value with a later timestamp
let passwordChangedCorrect = false;
if (targetAccount) {
  const newPasswordOk = targetAccount.password === 'NewEspresso!222' && targetAccount.password !== 'OldBrew!111';
  const baselineTs = new Date('2025-10-25T09:55:00Z');
  const changedTs = targetAccount.passwordLastChangedAt ? new Date(targetAccount.passwordLastChangedAt) : null;
  const timestampOk = !!changedTs && changedTs.getTime() > baselineTs.getTime();
  passwordChangedCorrect = newPasswordOk && timestampOk;
}

// CP2: Currently logged in as this account (after password change)
const loggedInWithNewPasswordAccount = !!targetAccount && currentAccountId === targetAccount.id;

checkpoints.push({ passed: passwordChangedCorrect, weight: 0.6 });
checkpoints.push({ passed: loggedInWithNewPasswordAccount, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
